async def process_card(cc, mes, ano, cvv, site_url, variant_id=None, proxy_str=None):
    gateway = "UNKNOWN"
    total_price = "0.00"
    currency = "USD"

    ourl = site_url if site_url.startswith('http') else f'https://{site_url}'
    payment_identifier = None
    proxy = parse_proxy(proxy_str) if proxy_str else None
    checkpoint_data = None
    running_total = "0.00"
    rid = None

    try:
        headers = {
            'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
            'Accept': 'application/json, text/plain, */*',
            'Accept-Language': 'en-US,en;q=0.9',
            'Content-Type': 'application/json',
            'Origin': ourl,
            'Referer': ourl,
        }

        address_info = pick_addr(ourl)
        country_code = address_info["countryCode"]

        firstName, lastName = Utils.get_random_name()
        email = Utils.generate_email(firstName, lastName)

        phone = address_info["phone"]
        street = address_info["address1"]
        city = address_info["city"]
        state = address_info["zoneCode"]
        s_zip = address_info["postalCode"]
        address2 = ""

        if not variant_id:
            info = await fetch_products(ourl, proxy_str)
            if isinstance(info, tuple) and info[0] is False:
                return False, info[1], gateway, total_price, currency
            variant_id = info['variant_id']

        connector = aiohttp.TCPConnector(ssl=False)
        timeout = aiohttp.ClientTimeout(total=30)

        async with aiohttp.ClientSession(connector=connector, timeout=timeout) as session:
            url = ourl
            cart = url + '/cart/add.js'
            checkout = url + '/checkout/'

            # Step 1: Add to Cart
            cart_headers = {**headers, 'Content-Type': 'application/x-www-form-urlencoded'}
            cart_resp = await session.post(cart, data=f'id={variant_id}&quantity=1', headers=cart_headers, proxy=proxy)
            if cart_resp.status != 200:
                cart_headers_alt = {**headers, 'Content-Type': 'application/json'}
                cart_data = {'items': [{'id': int(variant_id), 'quantity': 1}]}
                cart_resp = await session.post(cart, json=cart_data, headers=cart_headers_alt, proxy=proxy)
            if cart_resp.status != 200:
                return False, f"Cart failed with status {cart_resp.status}", gateway, total_price, currency

            # Step 2: Initiate Checkout
            checkout_headers = {**headers, 'Accept': 'text/html,application/xhtml+xml'}
            response = await session.post(url=checkout, allow_redirects=True, headers=checkout_headers, proxy=proxy)
            checkout_url = str(response.url)

            attempt_token_match = re.search(r'/checkouts/cn/([^/?]+)', checkout_url or '')
            attempt_token = attempt_token_match.group(1) if attempt_token_match else ((checkout_url or '').split('/')[-1].split('?')[0])

            sst = response.headers.get('X-Checkout-One-Session-Token') or response.headers.get('x-checkout-one-session-token')
            text = await response.text()
            unescaped_text = text.replace('&quot;', '"').replace('&amp;', '&').replace('&#39;', "'")

            if not sst:
                sst = extract_between(text, 'name="serialized-sessionToken" content="&quot;', '&quot;')
            if not sst:
                sst = extract_between(text, 'name="serialized-sessionToken" content="', '"')
            if not sst:
                sst = extract_between(unescaped_text, '"serializedSessionToken":"', '"')
            if not sst:
                sst = extract_between(unescaped_text, 'data-session-token="', '"')
            if not sst:
                sst = extract_between(unescaped_text, '"sessionToken":"', '"')

            if 'login' in checkout_url.lower():
                return False, "Site requires login!", gateway, total_price, currency

            queueToken = (
                extract_between(text, 'queueToken&quot;:&quot;', '&quot;')
                or extract_between(unescaped_text, '"queueToken":"', '"')
            )
            stableId = (
                extract_between(text, 'stableId&quot;:&quot;', '&quot;')
                or extract_between(unescaped_text, '"stableId":"', '"')
            )
            merch = (
                extract_between(text, 'ProductVariantMerchandise/', '&quot;')
                or extract_between(text, 'ProductVariantMerchandise/', '&q')
                or extract_between(unescaped_text, '"merchandiseId":"gid://shopify/ProductVariantMerchandise/', '"')
            )
            if not merch:
                merch = str(variant_id)

            currency = 'USD'
            if 'currencyCode&quot;:&quot;' in text:
                currency = extract_between(text, 'currencyCode&quot;:&quot;', '&quot;') or 'USD'
            elif '"currencyCode":"' in unescaped_text:
                currency = extract_between(unescaped_text, '"currencyCode":"', '"') or 'USD'

            subtotal = (
                extract_between(text, 'subtotalBeforeTaxesAndShipping&quot;:{&quot;value&quot;:{&quot;amount&quot;:&quot;', '&quot;')
                or extract_between(unescaped_text, '"subtotalBeforeTaxesAndShipping":{"value":{"amount":"', '"')
            )
            if not subtotal:
                price_match = re.search(r'"price":\s*"([\d.]+)"', unescaped_text)
                subtotal = price_match.group(1) if price_match else "0.01"

            if not sst:
                return False, "Failed to get session token", gateway, total_price, currency

            headers.update({
                'shopify-checkout-client': 'checkout-web/1.0',
                'shopify-checkout-source': f'id="{attempt_token}", type="cn"',
                'x-checkout-one-session-token': sst,
            })

            graphql_url = f'https://{urlparse(ourl).netloc}/checkouts/unstable/graphql'
            params = {'operationName': 'Proposal'}

            json_data = {
                'query': QUERY_PROPOSAL_SHIPPING,
                'variables': {
                    'sessionInput': {'sessionToken': sst},
                    'queueToken': queueToken or '',
                    'discounts': {'lines': [], 'acceptUnexpectedDiscounts': True},
                    'delivery': {
                        'deliveryLines': [{
                            'destination': {
                                'partialStreetAddress': {
                                    'address1': street, 'address2': address2, 'city': city,
                                    'countryCode': country_code, 'postalCode': s_zip,
                                    'firstName': firstName, 'lastName': lastName,
                                    'zoneCode': state, 'phone': phone
                                }
                            },
                            'selectedDeliveryStrategy': {
                                'deliveryStrategyMatchingConditions': {
                                    'estimatedTimeInTransit': {'any': True},
                                    'shipments': {'any': True}
                                },
                                'options': {}
                            },
                            'targetMerchandiseLines': {'any': True},
                            'deliveryMethodTypes': ['SHIPPING'],
                            'expectedTotalPrice': {'any': True},
                            'destinationChanged': True
                        }],
                        'noDeliveryRequired': [],
                        'useProgressiveRates': False,
                        'prefetchShippingRatesStrategy': None,
                        'supportsSplitShipping': True
                    },
                    'deliveryExpectations': {'deliveryExpectationLines': []},
                    'merchandise': {
                        'merchandiseLines': [{
                            'stableId': stableId or '1',
                            'merchandise': {
                                'productVariantReference': {
                                    'id': f'gid://shopify/ProductVariantMerchandise/{merch}',
                                    'variantId': f'gid://shopify/ProductVariant/{variant_id}',
                                    'properties': [],
                                    'sellingPlanId': None,
                                    'sellingPlanDigest': None
                                }
                            },
                            'quantity': {'items': {'value': 1}},
                            'expectedTotalPrice': {'value': {'amount': subtotal, 'currencyCode': currency}},
                            'lineComponentsSource': None,
                            'lineComponents': []
                        }]
                    },
                    'payment': {
                        'totalAmount': {'any': True},
                        'paymentLines': [],
                        'billingAddress': {
                            'streetAddress': {
                                'address1': '', 'city': '', 'countryCode': country_code,
                                'lastName': '', 'zoneCode': 'ENG', 'phone': ''
                            }
                        }
                    },
                    'buyerIdentity': {
                        'customer': {'presentmentCurrency': currency, 'countryCode': country_code},
                        'email': email,
                        'emailChanged': False,
                        'phoneCountryCode': country_code,
                        'marketingConsent': [{'email': {'value': email}}],
                        'shopPayOptInPhone': {'countryCode': country_code},
                        'rememberMe': False
                    },
                    'tip': {'tipLines': []},
                    'taxes': {
                        'proposedAllocations': None,
                        'proposedTotalAmount': {'value': {'amount': '0', 'currencyCode': currency}},
                        'proposedTotalIncludedAmount': None,
                        'proposedMixedStateTotalAmount': None,
                        'proposedExemptions': []
                    },
                    'note': {'message': None, 'customAttributes': []},
                    'localizationExtension': {'fields': []},
                    'nonNegotiableTerms': None,
                    'scriptFingerprint': {
                        'signature': None, 'signatureUuid': None,
                        'lineItemScriptChanges': [], 'paymentScriptChanges': [], 'shippingScriptChanges': []
                    },
                    'optionalDuties': {'buyerRefusesDuties': False}
                },
                'operationName': 'Proposal'
            }

            # Step 7: Send Proposal (Shipping) Request
            response, resp_text, _ = await make_graphql_request_with_captcha_handling(
                session, graphql_url, params, headers, json_data, checkout_url, max_retries=2
            )

            if not response:
                return False, f"Request failed: {resp_text}", gateway, total_price, currency
            if is_captcha_required(resp_text):
                return False, "CAPTCHA_REQUIRED", gateway, total_price, currency

            try:
                resp_json = json.loads(resp_text)
            except json.JSONDecodeError as e:
                return False, f"Invalid JSON response: {str(e)}", gateway, total_price, currency

            if 'errors' in resp_json:
                error_msgs = [e.get('message', str(e)) for e in resp_json.get('errors', [])[:3]]
                return False, f"GraphQL Error: {'; '.join(error_msgs)}", gateway, total_price, currency

            # Step 8: Parse Proposal Response
            try:
                session_data = resp_json['data']['session']
                negotiate = session_data['negotiate']
                result = negotiate['result']
                result_type = result.get('__typename', 'Unknown')

                if result_type == 'NegotiationResultAvailable':
                    pass
                elif result_type == 'CheckpointDenied':
                    return False, "Checkpoint Denied", gateway, total_price, currency
                elif result_type == 'Throttled':
                    return False, "Throttled", gateway, total_price, currency
                elif result_type == 'NegotiationResultFailed':
                    return False, "Negotiation failed", gateway, total_price, currency
                else:
                    return False, f"Unexpected result type: {result_type}", gateway, total_price, currency

                checkpoint_data = result.get('checkpointData')
                seller_proposal = result.get('sellerProposal')
                if seller_proposal is None:
                    return False, "Seller proposal is null", gateway, total_price, currency

                delivery_data = seller_proposal.get('delivery')
                running_total_data = seller_proposal.get('runningTotal')
                if not running_total_data:
                    return False, "No runningTotal in sellerProposal", gateway, total_price, currency
                running_total = running_total_data['value']['amount']

            except Exception:
                return False, "Failed to parse proposal response", gateway, total_price, currency

            # Step 9: Handle PendingTerms in Delivery
            delivery_typename = delivery_data.get('__typename', '')

            if delivery_typename == 'UnavailableTerms':
                return False, "Delivery not available: UnavailableTerms", gateway, total_price, currency

            elif delivery_typename == 'PendingTerms':
                poll_delay = delivery_data.get('pollDelay', 3)
                await asyncio.sleep(poll_delay)

                response, resp_text, _ = await make_graphql_request_with_captcha_handling(
                    session, graphql_url, params, headers, json_data, checkout_url, max_retries=1
                )
                if not response:
                    return False, "Retry after PendingTerms failed", gateway, total_price, currency
                try:
                    resp_json = json.loads(resp_text)
                except Exception:
                    return False, "Invalid JSON after retry", gateway, total_price, currency

                session_data = resp_json['data']['session']
                negotiate = session_data['negotiate']
                result = negotiate['result']
                if result.get('__typename') != 'NegotiationResultAvailable':
                    return False, f"Retry failed: {result.get('__typename')}", gateway, total_price, currency

                checkpoint_data = result.get('checkpointData')
                seller_proposal = result['sellerProposal']
                delivery_data = seller_proposal['delivery']
                running_total_data = seller_proposal['runningTotal']
                running_total = running_total_data['value']['amount']
                delivery_typename = delivery_data.get('__typename', '')

                if delivery_typename != 'FilledDeliveryTerms':
                    return False, f"Delivery still pending after retry: {delivery_typename}", gateway, total_price, currency

            elif delivery_typename != 'FilledDeliveryTerms':
                return False, f"Delivery not available: {delivery_typename}", gateway, total_price, currency

            # Step 10: Extract Delivery Strategies & Shipping Rates
            shipping_amount = "0.00"
            shipping_rate_handle = None
            delivery_strategy_handle = None
            tax_amount = "0.00"

            try:
                delivery_lines = delivery_data.get('deliveryLines', [])
                if not delivery_lines:
                    return False, "No delivery lines available", gateway, total_price, currency

                for dline in delivery_lines:
                    for strategy in dline.get('availableDeliveryStrategies', []):
                        if strategy.get('__typename') == 'CompleteDeliveryStrategy':
                            handle = strategy.get('handle', '')
                            amount_obj = strategy.get('amountAfterDiscounts', {}) or strategy.get('amount', {})
                            raw_amount = amount_obj.get('value', {}).get('amount') if isinstance(amount_obj, dict) else None
                            if raw_amount and handle:
                                try:
                                    if shipping_rate_handle is None or float(raw_amount) < float(shipping_amount or '0'):
                                        shipping_amount = raw_amount
                                        shipping_rate_handle = handle
                                        delivery_strategy_handle = handle
                                except (ValueError, TypeError):
                                    continue

                if not delivery_strategy_handle:
                    for dline in delivery_lines:
                        selected = dline.get('selectedDeliveryStrategy', {})
                        handle = selected.get('handle', '')
                        if handle:
                            delivery_strategy_handle = handle
                            shipping_rate_handle = handle
                            amount_obj = selected.get('amount', {})
                            if isinstance(amount_obj, dict):
                                shipping_amount = amount_obj.get('value', {}).get('amount', '0.00')
                            break

                if not delivery_strategy_handle:
                    return False, "No delivery strategy found", gateway, total_price, currency

            except Exception:
                return False, "Failed to parse delivery strategies", gateway, total_price, currency

            # Step 11: Extract Payment Method
            try:
                payment_data = seller_proposal.get('payment', {})
                if payment_data.get('__typename') != 'FilledPaymentTerms':
                    return False, "Payment not available", gateway, total_price, currency

                for apt in payment_data.get('availablePaymentLines', []):
                    pm = apt.get('paymentMethod', {})
                    ptype = pm.get('__typename', '')
                    if ptype == 'PaymentProvider':
                        gateway = pm.get('name', 'shopify_payments')
                        payment_identifier = pm.get('paymentMethodIdentifier') or pm.get('id')
                        if payment_identifier:
                            break
                    elif ptype == 'CustomOnsiteProvider':
                        gateway = pm.get('name', 'custom')
                        payment_identifier = pm.get('paymentMethodIdentifier')
                        if payment_identifier:
                            break

                if not payment_identifier:
                    for apt in payment_data.get('availablePaymentLines', []):
                        pm = apt.get('paymentMethod', {})
                        pid = pm.get('paymentMethodIdentifier') or pm.get('id')
                        if pid:
                            gateway = pm.get('name', 'shopify_payments')
                            payment_identifier = pid
                            break

                if not payment_identifier:
                    return False, "No payment identifier found", gateway, total_price, currency

            except Exception:
                return False, "Failed to parse payment", gateway, total_price, currency

            # Step 12: Extract Tax
            try:
                tax_data = seller_proposal.get('tax', {})
                if tax_data.get('__typename') == 'FilledTaxTerms':
                    total_tax = tax_data.get('totalTaxAmount', {})
                    if isinstance(total_tax, dict):
                        tax_amount = total_tax.get('value', {}).get('amount', '0.00')
            except Exception:
                tax_amount = "0.00"

            # Step 13: Total Price
            try:
                total_price = str(float(running_total) + float(shipping_amount) + float(tax_amount))
            except (ValueError, TypeError):
                total_price = running_total

            # Step 14: Send Delivery Proposal
            proposal_variables = {
                'sessionInput': {'sessionToken': sst},
                'queueToken': queueToken or '',
                'checkpointData': checkpoint_data or '',
                'discounts': {'lines': [], 'acceptUnexpectedDiscounts': True},
                'delivery': {
                    'deliveryLines': [{
                        'destination': {
                            'partialStreetAddress': {
                                'address1': street, 'address2': address2, 'city': city,
                                'countryCode': country_code, 'postalCode': s_zip,
                                'firstName': firstName, 'lastName': lastName,
                                'zoneCode': state, 'phone': phone
                            }
                        },
                        'selectedDeliveryStrategy': {
                            'completeDeliveryStrategy': {'handle': delivery_strategy_handle}
                        },
                        'targetMerchandiseLines': {'any': True},
                        'deliveryMethodTypes': ['SHIPPING'],
                        'expectedTotalPrice': {'value': {'amount': shipping_amount, 'currencyCode': currency}},
                        'destinationChanged': True
                    }],
                    'noDeliveryRequired': [],
                    'useProgressiveRates': False,
                    'prefetchShippingRatesStrategy': None,
                    'supportsSplitShipping': True
                },
                'merchandise': {
                    'merchandiseLines': [{
                        'stableId': stableId or '1',
                        'merchandise': {
                            'productVariantReference': {
                                'id': f'gid://shopify/ProductVariantMerchandise/{merch}',
                                'variantId': f'gid://shopify/ProductVariant/{variant_id}',
                                'properties': [],
                                'sellingPlanId': None,
                                'sellingPlanDigest': None
                            }
                        },
                        'quantity': {'items': {'value': 1}},
                        'expectedTotalPrice': {'value': {'amount': running_total, 'currencyCode': currency}},
                        'lineComponentsSource': None,
                        'lineComponents': []
                    }]
                },
                'payment': {
                    'totalAmount': {'value': {'amount': total_price, 'currencyCode': currency}},
                    'paymentLines': [{
                        'stableId': '0',
                        'amount': {'value': {'amount': total_price, 'currencyCode': currency}},
                        'dueAt': 'now',
                        'paymentMethod': {'paymentMethodReference': {'paymentMethodIdentifier': payment_identifier}}
                    }],
                    'billingAddress': {
                        'streetAddress': {
                            'address1': street, 'address2': address2, 'city': city,
                            'countryCode': country_code, 'firstName': firstName,
                            'lastName': lastName, 'zoneCode': state,
                            'postalCode': s_zip, 'phone': phone
                        }
                    }
                },
                'buyerIdentity': {
                    'customer': {'presentmentCurrency': currency, 'countryCode': country_code},
                    'email': email, 'emailChanged': False, 'phoneCountryCode': country_code,
                    'marketingConsent': [{'email': {'value': email}}],
                    'shopPayOptInPhone': {'countryCode': country_code}, 'rememberMe': False
                },
                'tip': {'tipLines': []},
                'taxes': {
                    'proposedAllocations': None,
                    'proposedTotalAmount': {'value': {'amount': tax_amount, 'currencyCode': currency}},
                    'proposedTotalIncludedAmount': None,
                    'proposedMixedStateTotalAmount': None,
                    'proposedExemptions': []
                },
                'note': {'message': None, 'customAttributes': []},
                'localizationExtension': {'fields': []},
                'nonNegotiableTerms': None,
                'scriptFingerprint': {
                    'signature': None, 'signatureUuid': None,
                    'lineItemScriptChanges': [], 'paymentScriptChanges': [], 'shippingScriptChanges': []
                },
                'optionalDuties': {'buyerRefusesDuties': False}
            }

            delivery_json_data = {'query': QUERY_PROPOSAL_DELIVERY, 'variables': proposal_variables, 'operationName': 'Proposal'}

            delivery_response, delivery_text, _ = await make_graphql_request_with_captcha_handling(
                session, graphql_url, params, headers, delivery_json_data, checkout_url, max_retries=2
            )

            if not delivery_response:
                return False, f"Delivery request failed: {delivery_text}", gateway, total_price, currency
            if is_captcha_required(delivery_text):
                return False, "CAPTCHA_REQUIRED", gateway, total_price, currency

            try:
                delivery_json = json.loads(delivery_text)
            except json.JSONDecodeError:
                return False, "Invalid delivery response", gateway, total_price, currency

            try:
                del_result = delivery_json['data']['session']['negotiate']['result']
                if del_result.get('__typename') not in ('NegotiationResultAvailable',):
                    return False, f"Delivery failed: {del_result.get('__typename')}", gateway, total_price, currency
                checkpoint_data = del_result.get('checkpointData') or checkpoint_data
            except Exception:
                return False, "Failed to parse delivery response", gateway, total_price, currency

            # Step 15: Vault Credit Card
            try:
                vault_url = 'https://checkout.pci.shopifyinc.com/sessions'
                vault_headers = {
                    'User-Agent': headers.get('User-Agent', ''),
                    'Accept': 'application/json',
                    'Content-Type': 'application/json',
                    'Origin': 'https://checkout.shopifycs.com',
                    'Referer': 'https://checkout.shopifycs.com/',
                }
                vault_data = {
                    'credit_card': {
                        'number': cc,
                        'name': f'{firstName} {lastName}',
                        'verification_value': cvv,
                        'month': int(mes),
                        'year': int(ano)
                    }
                }
                vault_resp = await session.post(vault_url, headers=vault_headers, json=vault_data, proxy=proxy)
                vault_text = await vault_resp.text()

                if vault_resp.status != 200:
                    try:
                        vault_msg = json.loads(vault_text).get('message', f'Vault failed: HTTP {vault_resp.status}')
                    except Exception:
                        vault_msg = f"Vault failed: HTTP {vault_resp.status}"
                    return False, vault_msg, gateway, total_price, currency

                vault_json = json.loads(vault_text)
                payment_session_id = vault_json.get('id')
                if not payment_session_id:
                    return False, "No payment session ID from vault", gateway, total_price, currency

            except Exception as e:
                return False, f"Vault error: {str(e)}", gateway, total_price, currency

            # Step 16: Submit Mutation
            submit_variables = {
                'sessionInput': {'sessionToken': sst},
                'queueToken': queueToken or '',
                'checkpointData': checkpoint_data or '',
                'discounts': {'lines': [], 'acceptUnexpectedDiscounts': True},
                'delivery': {
                    'deliveryLines': [{
                        'destination': {
                            'partialStreetAddress': {
                                'address1': street, 'address2': address2, 'city': city,
                                'countryCode': country_code, 'postalCode': s_zip,
                                'firstName': firstName, 'lastName': lastName,
                                'zoneCode': state, 'phone': phone
                            }
                        },
                        'selectedDeliveryStrategy': {'completeDeliveryStrategy': {'handle': delivery_strategy_handle}},
                        'targetMerchandiseLines': {'any': True},
                        'deliveryMethodTypes': ['SHIPPING'],
                        'expectedTotalPrice': {'value': {'amount': shipping_amount, 'currencyCode': currency}},
                        'destinationChanged': True
                    }],
                    'noDeliveryRequired': [], 'useProgressiveRates': False,
                    'prefetchShippingRatesStrategy': None, 'supportsSplitShipping': True
                },
                'merchandise': {
                    'merchandiseLines': [{
                        'stableId': stableId or '1',
                        'merchandise': {
                            'productVariantReference': {
                                'id': f'gid://shopify/ProductVariantMerchandise/{merch}',
                                'variantId': f'gid://shopify/ProductVariant/{variant_id}',
                                'properties': [], 'sellingPlanId': None, 'sellingPlanDigest': None
                            }
                        },
                        'quantity': {'items': {'value': 1}},
                        'expectedTotalPrice': {'value': {'amount': running_total, 'currencyCode': currency}},
                        'lineComponentsSource': None, 'lineComponents': []
                    }]
                },
                'payment': {
                    'totalAmount': {'value': {'amount': total_price, 'currencyCode': currency}},
                    'paymentLines': [{
                        'stableId': '0',
                        'amount': {'value': {'amount': total_price, 'currencyCode': currency}},
                        'dueAt': 'now',
                        'paymentMethod': {
                            'directPaymentMethod': {
                                'sessionId': payment_session_id,
                                'vaultedPaymentMethodIdentifier': None,
                                'paymentAttributes': {}
                            }
                        }
                    }],
                    'billingAddress': {
                        'streetAddress': {
                            'address1': street, 'address2': address2, 'city': city,
                            'countryCode': country_code, 'firstName': firstName,
                            'lastName': lastName, 'zoneCode': state,
                            'postalCode': s_zip, 'phone': phone
                        }
                    }
                },
                'buyerIdentity': {
                    'customer': {'presentmentCurrency': currency, 'countryCode': country_code},
                    'email': email, 'emailChanged': False, 'phoneCountryCode': country_code,
                    'marketingConsent': [{'email': {'value': email}}],
                    'shopPayOptInPhone': {'countryCode': country_code}, 'rememberMe': False
                },
                'tip': {'tipLines': []},
                'taxes': {
                    'proposedAllocations': None,
                    'proposedTotalAmount': {'value': {'amount': tax_amount, 'currencyCode': currency}},
                    'proposedTotalIncludedAmount': None,
                    'proposedMixedStateTotalAmount': None,
                    'proposedExemptions': []
                },
                'note': {'message': None, 'customAttributes': []},
                'localizationExtension': {'fields': []},
                'nonNegotiableTerms': None,
                'scriptFingerprint': {
                    'signature': None, 'signatureUuid': None,
                    'lineItemScriptChanges': [], 'paymentScriptChanges': [], 'shippingScriptChanges': []
                },
                'optionalDuties': {'buyerRefusesDuties': False}
            }

            submit_json_data = {
                'query': MUTATION_SUBMIT,
                'variables': {
                    'input': submit_variables,
                    'attemptToken': attempt_token or '',
                    'metafields': [],
                    'postPurchaseInquiryResult': None,
                    'analytics': None
                },
                'operationName': 'SubmitForCompletion'
            }

            submit_response, submit_text, _ = await make_graphql_request_with_captcha_handling(
                session, graphql_url, params, headers, submit_json_data, checkout_url, max_retries=2
            )

            if not submit_response:
                return False, f"Submit request failed: {submit_text}", gateway, total_price, currency
            if is_captcha_required(submit_text):
                return False, "CAPTCHA_REQUIRED", gateway, total_price, currency

            try:
                submit_json = json.loads(submit_text)
            except json.JSONDecodeError:
                return False, "Invalid submit response", gateway, total_price, currency

            # Step 17: Parse Submit Response
            try:
                submit_data = submit_json.get('data', {}).get('submitForCompletion', {})
                submit_type = submit_data.get('__typename', 'Unknown')

                if submit_type in ('SubmitSuccess', 'SubmittedForCompletion', 'SubmitAlreadyAccepted'):
                    receipt = submit_data.get('receipt', {})
                    if receipt.get('__typename') == 'ProcessedReceipt':
                        return True, "ORDER_PLACED", gateway, total_price, currency
                    rid = receipt.get('id')
                    if receipt.get('__typename') == 'ActionRequiredReceipt':
                        return False, "OTP_REQUIRED", gateway, total_price, currency

                elif submit_type == 'SubmitFailed':
                    return False, f"CARD_DECLINED: {submit_data.get('reason', 'Payment failed')}", gateway, total_price, currency

                elif submit_type == 'SubmitRejected':
                    submit_errors = submit_data.get('errors', [])
                    if submit_errors:
                        for err in submit_errors:
                            err_code = err.get('code', '')
                            if err_code in ('PAYMENT_DECLINED', 'CARD_DECLINED', 'INSUFFICIENT_FUNDS',
                                           'EXPIRED_CARD', 'INVALID_CARD', 'INVALID_NUMBER',
                                           'CVV_FAILURE', 'CARD_TYPE_NOT_SUPPORTED'):
                                return False, f"CARD_DECLINED: {err_code}", gateway, total_price, currency
                            if err_code in ('THROTTLED', 'RATE_LIMITED'):
                                return False, f"RATE_LIMITED: {err_code}", gateway, total_price, currency
                        return False, f"REJECTED: {submit_errors[0].get('code', 'UNKNOWN')}", gateway, total_price, currency
                    return False, "Submit rejected", gateway, total_price, currency

                elif submit_type == 'Throttled':
                    return False, "RATE_LIMITED: Throttled", gateway, total_price, currency

                elif submit_type == 'CheckpointDenied':
                    return False, "Checkpoint Denied", gateway, total_price, currency

                else:
                    return False, f"Unexpected submit type: {submit_type}", gateway, total_price, currency

            except Exception:
                return False, "Failed to parse submit response", gateway, total_price, currency

            # Step 18: Polling
            if not rid:
                return False, "No receipt ID for polling", gateway, total_price, currency

            poll_json_data = {
                'query': QUERY_POLL,
                'variables': {'receiptId': rid, 'sessionToken': sst},
                'operationName': 'PollForReceipt'
            }

            max_polls = 5
            for poll_attempt in range(max_polls):
                await asyncio.sleep(3 if poll_attempt == 0 else 2)

                poll_response, poll_text, _ = await make_graphql_request_with_captcha_handling(
                    session, graphql_url, params, headers, poll_json_data, checkout_url, max_retries=1
                )

                if not poll_response:
                    if poll_attempt < max_polls - 1:
                        continue
                    return False, f"Poll failed: {poll_text}", gateway, total_price, currency

                try:
                    poll_json = json.loads(poll_text)
                    poll_data = poll_json.get('data', {}).get('receipt', {})
                    poll_type = poll_data.get('__typename', '')

                    if poll_type == 'ProcessedReceipt':
                        return True, "ORDER_PLACED", gateway, total_price, currency
                    elif poll_type in ('ProcessingReceipt', 'WaitingReceipt'):
                        continue
                    elif poll_type == 'FailedReceipt':
                        pe = poll_data.get('processingError', {})
                        if pe.get('__typename') == 'PaymentFailed':
                            return False, f"CARD_DECLINED: {pe.get('code', '')}", gateway, total_price, currency
                        return False, f"CARD_DECLINED: {pe.get('__typename')}", gateway, total_price, currency
                    elif poll_type == 'ActionRequiredReceipt':
                        return False, "OTP_REQUIRED", gateway, total_price, currency
                    elif poll_attempt < max_polls - 1:
                        continue
                    else:
                        return False, f"Unknown poll type: {poll_type}", gateway, total_price, currency

                except Exception:
                    if poll_attempt < max_polls - 1:
                        continue
                    return False, "Failed to parse poll response", gateway, total_price, currency

            return False, "Polling timeout", gateway, total_price, currency

    except aiohttp.ClientError as e:
        return False, f"Network error: {str(e)}", gateway, total_price, currency
    except Exception as e:
        return False, f"Unexpected error: {str(e)}", gateway, total_price, currency


