async def process_card_async(cc, mes, ano, cvv, site_url, variant_id=None, proxy_str=None):
    return await process_card(cc, mes, ano, cvv, site_url, variant_id, proxy_str)


# ═══════════════════════════════════════════════════════════════════
# Helper: Parse CC String
# ═══════════════════════════════════════════════════════════════════

def parse_cc_string(cc_string):
    if not cc_string:
        raise ValueError("CC string is empty")
    parts = cc_string.strip().split('|')
    if len(parts) != 4:
        raise ValueError(f"Invalid CC format. Expected CC|MM|YYYY|CVV, got {len(parts)} parts")
    cc, mes, ano, cvv = [p.strip() for p in parts]
    if not cc.isdigit() or len(cc) < 13 or len(cc) > 19:
        raise ValueError(f"Invalid card number: expected 13-19 digits, got {len(cc)}")
    if not mes.isdigit() or not (1 <= int(mes) <= 12):
        raise ValueError(f"Invalid month: {mes}")
    if not ano.isdigit() or len(ano) != 4:
        raise ValueError(f"Invalid year: {ano}")
    if not cvv.isdigit() or len(cvv) < 3 or len(cvv) > 4:
        raise ValueError(f"Invalid CVV: expected 3-4 digits, got {len(cvv)}")
    return cc, mes, ano, cvv


