app = Flask(__name__)
_worker_semaphore = threading.Semaphore(PARALLEL_WORKERS)


@app.route('/shopify', methods=['GET'])
def shopify_checker():
    try:
        site = request.args.get('site', '').strip()
        cc_string = request.args.get('cc', '').strip()
        variant_id = request.args.get('variant', '').strip() or None
        proxy_str = request.args.get('proxy', '').strip() or None

        if not site:
            return jsonify({"error": "site parameter is required"}), 400
        if not cc_string:
            return jsonify({"error": "cc parameter is required"}), 400

        cc, mes, ano, cvv = parse_cc_string(cc_string)
        result = asyncio.run(process_card_async(cc, mes, ano, cvv, site, variant_id, proxy_str))
        success, message, gateway, price, currency = result

        return jsonify({
            "Status": success,
            "Response": message,
            "Gateway": gateway,
            "Price": float(price) if price and price.replace('.', '', 1).replace('-', '', 1).isdigit() else 0.0,
            "Currency": currency,
            "cc": cc_string
        })
    except ValueError as e:
        return jsonify({"error": str(e), "Status": False}), 400
    except Exception as e:
        return jsonify({"error": f"Internal error: {str(e)}", "Status": False}), 500


@app.route('/shopify_parallel', methods=['GET'])
def shopify_parallel():
    try:
        site = request.args.get('site', '').strip()
        cc_string = request.args.get('cc', '').strip()
        variant_id = request.args.get('variant', '').strip() or None
        proxy_str = request.args.get('proxy', '').strip() or None

        if not site:
            return jsonify({"error": "site parameter is required"}), 400
        if not cc_string:
            return jsonify({"error": "cc parameter is required"}), 400

        cc, mes, ano, cvv = parse_cc_string(cc_string)

        acquired = _worker_semaphore.acquire(timeout=5)
        if not acquired:
            return jsonify({"Status": False, "Response": "Server busy", "Gateway": "", "Price": 0.0, "Currency": "", "cc": cc_string}), 429

        try:
            future = _executor.submit(run_card_check_parallel, cc, mes, ano, cvv, site, variant_id, proxy_str)
            try:
                success, message, gateway, price, currency = future.result(timeout=PARALLEL_TIMEOUT)
            except FuturesTimeoutError:
                return jsonify({"Status": False, "Response": "Request timed out", "Gateway": "", "Price": 0.0, "Currency": "", "cc": cc_string}), 504

            return jsonify({
                "Status": success,
                "Response": message,
                "Gateway": gateway,
                "Price": float(price) if price and price.replace('.', '', 1).replace('-', '', 1).isdigit() else 0.0,
                "Currency": currency,
                "cc": cc_string
            })
        finally:
            _worker_semaphore.release()
    except ValueError as e:
        return jsonify({"error": str(e), "Status": False}), 400
    except Exception as e:
        return jsonify({"error": f"Internal error: {str(e)}", "Status": False}), 500


@app.route('/stats', methods=['GET'])
def stats():
    count = 0
    for _ in range(PARALLEL_WORKERS):
        if _worker_semaphore.acquire(blocking=False):
            count += 1
    for _ in range(count):
        _worker_semaphore.release()
    return jsonify({
        "max_workers": PARALLEL_WORKERS,
        "available_slots": count,
        "busy_workers": PARALLEL_WORKERS - count,
        "timeout_seconds": PARALLEL_TIMEOUT
    })


@app.route('/health', methods=['GET'])
def health():
    return jsonify({"status": "ok"}), 200


if __name__ == '__main__':
    parser = argparse.ArgumentParser(description='Shopify Checkout API Server')
    parser.add_argument('--host', default='0.0.0.0')
    parser.add_argument('--port', type=int, default=5000)
    parser.add_argument('--debug', action='store_true')
    parser.add_argument('--workers', type=int, default=PARALLEL_WORKERS)
    args = parser.parse_args()

    if args.workers != PARALLEL_WORKERS:
        PARALLEL_WORKERS = args.workers
        _executor.shutdown(wait=False)
        _executor = ThreadPoolExecutor(max_workers=PARALLEL_WORKERS)
        _worker_semaphore = threading.Semaphore(PARALLEL_WORKERS)

    print(f"Starting Shopify Checkout API Server on {args.host}:{args.port}")
    print(f"Max parallel workers: {PARALLEL_WORKERS}")
    app.run(host=args.host, port=args.port, debug=args.debug)
